CREATE TABLE IF NOT EXISTS public.catalog (
    id SERIAL PRIMARY KEY,
    cost INTEGER NOT NULL,
    city TEXT NOT NULL,
    user_email TEXT NOT NULL,
    description TEXT,
    photo TEXT NOT NULL,
    name TEXT NOT NULL,
    date_in DATE NOT NULL,
    date_out DATE NOT NULL
);

CREATE TABLE IF NOT EXISTS public.reviews (
    id SERIAL PRIMARY KEY,
    name TEXT,
    text TEXT NOT NULL,
    stars INTEGER NOT NULL CHECK (stars BETWEEN 1 AND 5),
    catalog_id INTEGER NOT NULL REFERENCES public.catalog(id) ON DELETE CASCADE,
    create_date TIMESTAMP NOT NULL DEFAULT NOW()
);

DO $$
BEGIN
    IF (SELECT COUNT(*) FROM public.catalog) = 0 THEN
        INSERT INTO public."catalog" ("cost",city,user_email,description,photo,name,date_in,date_out) VALUES
        (45000,'Ханой','travel@vietnamtour.com','Экскурсионный тур по Ханою: посещение мавзолея Хо Ши Мина, Храма литературы, озера Возвращенного меча и старого квартала. Включено проживание в отеле 3*, завтраки, трансфер.','https://img.hostelworldblog.com/blog/wp-content/uploads/2024/10/dreamstimesmall_310938107.jpg','Открытие Ханоя - 3 дня','2024-05-15 09:00:00','2024-05-18 18:00:00'),
        (65000,'Халонг','travel@vietnamtour.com','Круиз по заливу Халонг на 3 дня/2 ночи. Посещение удивительных пещер, каякинг, плавание, мастер-класс по приготовлению вьетнамских блюд. Проживание на круизном лайере 4*, полный пансион.','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRAh8Y6iZP12ZJVQT6o1_Qh8fNKzh3e2YTHsw&s','Жемчужина Халонг - круиз','2024-06-10 12:00:00','2024-06-13 09:00:00'),
        (38000,'Хюэ','travel@vietnamtour.com','Императорский тур в древнюю столицу. Посещение Запретного города, императорских гробниц, пагоды Тхьенму, прогулка по реке Ароматов. Включено проживание, экскурсии с гидом.','https://upload.wikimedia.org/wikipedia/commons/2/2f/Ho%C3%A0ng_th%C3%A0nh_Hu%E1%BA%BF.jpg','Императорское наследие Хюэ','2024-05-25 08:00:00','2024-05-28 17:00:00'),
        (55000,'Дананг','travel@vietnamtour.com','Отдых на пляже Мой Не (Китайский пляж) с экскурсиями. Посещение мраморных гор, Золотого моста (руки Будды), парка развлечений Бана Хиллс. Проживание в отеле 4*, завтраки.','https://blog-cdn.aviata.kz/posts/thumbnails/0_97fd4a1895b5371e88d7e4ccd206aabfbe3ca6ececd8a36e9deb12b8ff94091d.webp','Пляжный рай Дананг','2024-07-05 14:00:00','2024-07-10 11:00:00'),
        (72000,'Хойан','travel@vietnamtour.com','Погружение в атмосферу древнего города. Экскурсии по старому городу, прогулка на лодках с фонариками, мастер-класс по созданию шелковых фонарей, пляжный отдых. Проживание в бутик-отеле.','https://fs.tonkosti.ru/sized/c800x800/dl/lk/dllkplcsm1kcc840ck4g4w4ck.jpg','Сказочный Хойан','2024-06-20 10:00:00','2024-06-25 15:00:00'),
        (49000,'Нячанг','travel@vietnamtour.com','Пляжный отдых и островные экскурсии. Посещение острова Винперл с аквапарком, дайвинг, грязевые ванны, морская прогулка. Проживание в отеле 3*, завтраки и обеды.','https://cdn2.tu-tu.ru/image/pagetree_node_data/2/dd481f086389ad07debeca9e778ab587/','Жемчужина Нячанга','2024-08-01 12:00:00','2024-08-07 10:00:00'),
        (82000,'Хошимин','travel@vietnamtour.com','Путешествие по Южному Вьетнаму. Экскурсии по Сайгону, посещение туннелей Кути, дельты Меконга с плавучим рынком. Проживание в отеле 4*, экскурсионная программа.','https://resize.tripster.ru/JJ4gWYzHujKNnNucyPp1WLMqz14=/fit-in/1220x600/filters:no_upscale()/https://cdn.tripster.ru/photos/c92c4b7c-5f89-4f61-aa19-9f45f78f87ef.jpg','Сайгонские приключения','2024-09-10 08:00:00','2024-09-16 19:00:00'),
        (68000,'Фукуок','travel@vietnamtour.com','Отдых на райском острове. Пляжный отдых, снорклинг на коралловых рифах, посещение жемчужной фермы, национального парка Фукуок. Проживание в курортном отеле 4*, завтраки.','https://upload.wikimedia.org/wikipedia/commons/6/6e/Bai-sao-phu-quoc-tuonglamphotos.jpg','Райский Фукуок','2024-10-05 14:00:00','2024-10-12 12:00:00'),
        (43000,'Шапа','travel@vietnamtour.com','Треккинг в горах Фансипан. Посещение деревень народностей Хмонг, Дао, осмотр террасных полей, восхождение на крышу Индокитая. Включено проживание, гид, питание.','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcREAQWiPA2ejWYV7O4LtF_Ihh_rVNjNhxeEQw&s','Горные тропы Шапы','2024-11-01 07:00:00','2024-11-06 16:00:00'),
        (75000,'Муйне','travel@vietnamtour.com','Сёрф-тур на пляжах Муйне. Кайтсёрфинг, посещение белых и красных дюн, рыбацкой деревни, ручьё Фейри Стрим. Проживание в бунгало у океана, завтраки, трансфер.','https://irecommend.ru/sites/default/files/product-images/283777/VbPjNZoK1BSrkNKToAxGLw.jpg','Приключения в Муйне','2024-12-15 11:00:00','2024-12-22 10:00:00');
    END IF;
END $$;

DO $$
BEGIN
    IF (SELECT COUNT(*) FROM public.reviews) = 0 THEN
        INSERT INTO public.reviews (name, text, stars, catalog_id, create_date) VALUES
        ('Анна Смирнова', 'Тур просто потрясающий! Вьетнам покорил своей природой и кухней. Отдельное спасибо гиду за организацию экскурсии в бухту Халонг. Еда очень вкусная и необычная. Отель выбрали отличный, с видом на море. Обязательно вернёмся ещё!', 5, 1, NOW() - INTERVAL '5 days'),
        ('Иван Петров', 'Всё понравилось, но было слишком много переездов. За 10 дней объехали полстраны — от Ханоя до Хошимина. Места шикарные, особенно Хойан и пляжи Нячанга. Организация на 4, можно было добавить побольше свободного времени.', 4, 1, NOW() - INTERVAL '12 days'),
        ('Елена Морозова', 'Ожидала большего от сервиса. В отеле были проблемы с горячей водой, гид решал их почти сутки. Страна красивая, но на такой тур я бы не советовала ехать с маленькими детьми — очень шумно на улицах и своеобразная гигиена.', 3, 2, NOW() - INTERVAL '3 days'),
        ('Дмитрий Козлов', 'Это был лучший отпуск в моей жизни! Вьетнам — сказка для бюджетных путешествий, но с высоким уровнем комфорта. Советую всем попробовать уличный фо-бо и яйцо столетней выдержки (на свой страх и риск).', 5, 1, NOW() - INTERVAL '1 day'),
        ('Ольга Соколова', 'Очень разочарована. Тур не соответствовал заявленной программе. Вместо 4 экскурсий провели 2, отель в Дананге подменили на более плохой. Звёзды только за отзывчивость местных жителей.', 2, 3, NOW() - INTERVAL '7 days'),
        ('Михаил Ткаченко', 'Вьетнам — огонь! Особенно понравился кросс на квадроциклах по дюнам Муйне. Организация тура на высоте, гид говорил по-русски отлично. Кормили очень сытно, отдельное спасибо за фруктовые тарелки каждый день.', 5, 1, NOW() - INTERVAL '20 days'),
        ('Наталья Ильина', 'Нормальный тур за свои деньги. Не ждите люкса, но для знакомства со страной подойдёт. Было душно, комары кусали, зато дешево и колоритно. Поставлю нейтральную оценку.', 3, 4, NOW() - INTERVAL '2 days'),
        ('Алексей Фёдоров', 'Не рекомендую этот тур тем, кто ценит комфорт. Автобус был старый, кондиционер работал плохо. Экскурсия на фанерный завод — пустая трата времени. Страна сама по себе красивая, но организация тура хромает.', 2, 3, NOW() - INTERVAL '15 days'),
        ('Виктория Дорофеева', 'Влюбилась во Вьетнам с первого дня! Программа тура очень насыщенная: Марбл Маунтинс, старый туннели Кути, королевский дворец в Хюэ. Спасибо за этот восторг!', 5, 1, NOW() - INTERVAL '10 days'),
        ('Сергей Васильев', 'Тур средний. С одной стороны, море и пляжи шикарные, с другой — навязчивые торговцы на каждом шагу портят отдых. В отеле убирали плохо, гид еле говорил по-русски. Больше тройки не заслуживает.', 3, 2, NOW() - INTERVAL '18 days');
    END IF;
END $$;
